"use client";

import { type SelectProps, Select as SelectRoot } from "./select";
import { SelectContent, type SelectContentProps } from "./select-content";
import { SelectEmpty, type SelectEmptyProps } from "./select-empty";
import { SelectItem, type SelectItemProps } from "./select-item";
import { SelectSearch, type SelectSearchProps } from "./select-search";
import { SelectTags, type SelectTagsProps } from "./select-tags";
import { SelectTrigger, type SelectTriggerProps } from "./select-trigger";
import {
  SelectValue,
  type SelectValueDisplay,
  type SelectValueProps,
  type SelectValueRenderProps,
} from "./select-value";

/**
 * Dropdown select with search, multiple selection, card variant, and controlled keyboard
 * integration points. 8 composable parts.
 */
const Select = Object.assign(SelectRoot, {
  Trigger: SelectTrigger,
  Content: SelectContent,
  Item: SelectItem,
  Search: SelectSearch,
  Value: SelectValue,
  Empty: SelectEmpty,
  Tags: SelectTags,
});

export { Select, type SelectProps };
export { SelectTrigger, type SelectTriggerProps };
export { SelectContent, type SelectContentProps };
export { SelectItem, type SelectItemProps };
export { SelectSearch, type SelectSearchProps };
export { SelectValue, type SelectValueProps, type SelectValueDisplay, type SelectValueRenderProps };
export { SelectEmpty, type SelectEmptyProps };
export { SelectTags, type SelectTagsProps };

"use client";

import { cva } from "class-variance-authority";
import {
  type AriaAttributes,
  Children,
  type ComponentPropsWithoutRef,
  isValidElement,
  type ReactNode,
  type Ref,
  useMemo,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { cn } from "@/lib/utils";
import { SelectContext, type SelectOptionMetadata } from "./select-context";
import { SelectItem, type SelectItemProps } from "./select-item";
import { SelectSearch } from "./select-search";
import { getNodeText } from "./selection";
import { type UseSelectStateOptions, useSelectState } from "./use-state-machine";

/** Props for select base. */
interface SelectBaseProps<TValue extends string = string>
  extends Omit<ComponentPropsWithoutRef<"div">, "defaultValue" | "onChange" | "id"> {
  /** Controlled open state. Pair with onOpenChange. */
  open?: boolean;
  /** Called when open state changes. */
  onOpenChange?: (open: boolean) => void;
  /**
   * Initial open state for uncontrolled usage. Useful with variant="card" for a settings-panel
   * layout that renders its list immediately.
   */
  defaultOpen?: boolean;
  /** Controlled highlighted item id. Pair with onHighlightChange. */
  highlighted?: TValue | null;
  /** Called when the highlighted item changes via keyboard or search. */
  onHighlightChange?: (value: TValue | null) => void;
  /** Disable the trigger and prevent open. */
  disabled?: boolean;
  /**
   * Visual treatment. "card" renders the inline settings-panel layout (combine with
   * defaultOpen).
   */
  variant?: "default" | "card";
  /** Width preset for the Select container. "full" fills the parent. */
  width?: "sm" | "md" | "lg" | "full";
  /** Name for the hidden form input that participates in native form submission. */
  name?: string;
  /** Mark the select as required for native form validation. */
  required?: boolean;
  /** ARIA invalid state forwarded to the rendered control. */
  "aria-invalid"?: AriaAttributes["aria-invalid"];
  /** ID applied to the rendered element. */
  id?: string;
  /** ID of the element that describes this component. */
  "aria-describedby"?: string;
  /** ID of the element that labels this component. */
  "aria-labelledby"?: string;
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
}

/** Props for select in single-selection mode. */
interface SelectSingleProps<TValue extends string = string> extends SelectBaseProps<TValue> {
  /** Enable multi-select. value/onChange become string[]. */
  multiple?: false;
  /** Controlled selected value. string[] when multiple, string in single mode. */
  value?: TValue;
  /** Called when the selection changes. */
  onChange?: (value: TValue) => void;
  /** Initial selected value for uncontrolled usage. */
  defaultValue?: TValue;
}

/** Props for select in multiple-selection mode. */
interface SelectMultipleProps<TValue extends string = string> extends SelectBaseProps<TValue> {
  /** Enable multi-select. value/onChange become string[]. */
  multiple: true;
  /** Controlled selected value. string[] when multiple, string in single mode. */
  value?: TValue[];
  /** Called when the selection changes. */
  onChange?: (value: TValue[]) => void;
  /** Initial selected value for uncontrolled usage. */
  defaultValue?: TValue[];
}

/** Props for select. */
export type SelectProps<TValue extends string = string> =
  | SelectSingleProps<TValue>
  | SelectMultipleProps<TValue>;

const selectRootVariants = cva("relative", {
  variants: {
    variant: {
      default: "",
      card: "border border-foreground bg-background shadow-[8px_8px_0px_0px_color-mix(in_srgb,var(--border)_50%,transparent)]",
    },
    width: {
      sm: "w-48",
      md: "w-64",
      lg: "w-80",
      full: "w-full",
    },
  },
  defaultVariants: { variant: "default" },
});

/** Options for derived select state. */
interface DerivedSelectStateOptions {
  /** open controlled used by derived select state. */
  openControlled: boolean;
  /** value controlled used by derived select state. */
  valueControlled: boolean;
  /** highlighted controlled used by derived select state. */
  highlightedControlled: boolean;
  /** searchable used by derived select state. */
  searchable: boolean;
  /** seed options used by derived select state. */
  seedOptions: ReadonlyMap<string, SelectOptionMetadata>;
}

// Single typed boundary for the public TValue -> internal string narrowing.
// value/defaultValue/highlighted widen covariantly; only the value/highlight
// callbacks are contravariant, so they get an explicit (identity-preserving)
// cast here instead of scattering casts across the component body.
function buildSelectStateOptions<TValue extends string>(
  props: SelectProps<TValue>,
  derived: DerivedSelectStateOptions,
): UseSelectStateOptions {
  const shared = {
    open: props.open,
    openControlled: derived.openControlled,
    onOpenChange: props.onOpenChange,
    defaultOpen: props.defaultOpen,
    valueControlled: derived.valueControlled,
    highlighted: props.highlighted ?? undefined,
    highlightedControlled: derived.highlightedControlled,
    onHighlightChange: props.onHighlightChange as ((value: string | null) => void) | undefined,
    disabled: props.disabled ?? false,
    searchable: derived.searchable,
    variant: props.variant ?? "default",
    ariaInvalid: props["aria-invalid"],
    ariaDescribedBy: props["aria-describedby"],
    ariaLabelledBy: props["aria-labelledby"],
    triggerIdProp: props.id,
    required: props.required,
    seedOptions: derived.seedOptions,
  };

  if (props.multiple) {
    return {
      ...shared,
      multiple: true,
      value: props.value,
      defaultValue: props.defaultValue,
      onChange: props.onChange as ((value: string[]) => void) | undefined,
    };
  }
  return {
    ...shared,
    multiple: false,
    value: props.value,
    defaultValue: props.defaultValue,
    onChange: props.onChange as ((value: string) => void) | undefined,
  };
}

/**
 * Dropdown select with search, multiple selection, card variant, and controlled keyboard
 * integration points. 8 composable parts.
 */
export function Select<TValue extends string = string>(props: SelectProps<TValue>) {
  const {
    children,
    className,
    ref,
    width,
    name,
    required,
    disabled = false,
    variant = "default",
    // Destructured only to keep select-specific props off the wrapper <div>;
    // the state machine reads them from the discriminated `props` below.
    open: _open,
    onOpenChange: _onOpenChange,
    defaultOpen: _defaultOpen,
    value: _value,
    onChange: _onChange,
    defaultValue: _defaultValue,
    highlighted: _highlighted,
    onHighlightChange: _onHighlightChange,
    multiple: _multiple,
    "aria-invalid": _ariaInvalid,
    id: _id,
    "aria-describedby": _ariaDescribedBy,
    "aria-labelledby": _ariaLabelledBy,
    ...rootProps
  } = props;
  const searchable = containsSelectSearchElement(children);
  // Seed labels for direct-child items so the trigger/value display works while
  // the (portaled) dropdown is closed and its items are unmounted. Registration
  // is authoritative whenever items are mounted (open) and is the only path that
  // resolves wrapper-rendered or dynamically composed items.
  const seedOptions = useMemo(() => collectSeedOptions(children), [children]);

  const stateOptions = buildSelectStateOptions(props, {
    openControlled: "open" in props,
    valueControlled: "value" in props,
    highlightedControlled: "highlighted" in props,
    searchable,
    seedOptions,
  });

  const { contextValue, wrapperRef } = useSelectState(stateOptions);
  const composedRef = useComposedRefs(wrapperRef, ref);

  return (
    <SelectContext value={contextValue}>
      <div
        {...rootProps}
        ref={composedRef}
        className={cn(selectRootVariants({ variant, width: width ?? undefined }), className)}
      >
        {children}
        {(name || required) &&
          (Array.isArray(contextValue.value) ? (
            <>
              <select
                name={name}
                multiple
                value={contextValue.value}
                required={required}
                disabled={disabled}
                tabIndex={-1}
                aria-hidden={true}
                className="sr-only"
                // Value is driven by the custom select; the no-op keeps this
                // hidden form mirror controlled without React's warning.
                onChange={() => {}}
                onInvalid={(event) => {
                  event.preventDefault();
                  contextValue.onNativeInvalid();
                }}
              >
                {contextValue.value.map((v) => (
                  <option key={v} value={v}>
                    {v}
                  </option>
                ))}
              </select>
              {required && (
                <input
                  type="checkbox"
                  required
                  checked={contextValue.value.length > 0}
                  disabled={disabled}
                  tabIndex={-1}
                  aria-hidden={true}
                  readOnly
                  className="sr-only"
                  onInvalid={(event) => {
                    event.preventDefault();
                    contextValue.onNativeInvalid();
                  }}
                />
              )}
            </>
          ) : (
            <select
              name={name}
              value={contextValue.value ?? ""}
              required={required}
              disabled={disabled}
              tabIndex={-1}
              aria-hidden={true}
              className="sr-only"
              // Value is driven by the custom select; the no-op keeps this
              // hidden form mirror controlled without React's warning.
              onChange={() => {}}
              onInvalid={(event) => {
                event.preventDefault();
                contextValue.onNativeInvalid();
              }}
            >
              <option value="" />
              {contextValue.value !== null && (
                <option value={contextValue.value}>{contextValue.value}</option>
              )}
            </select>
          ))}
      </div>
    </SelectContext>
  );
}

function containsSelectSearchElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === SelectSearch) return true;
    return containsSelectSearchElement(child.props.children);
  });
}

// Static seed for direct-child SelectItems. Used only to display the selected
// label while the dropdown is closed (items unmounted). It deliberately does NOT
// gate selectability — mounted items register through context, which is the only
// path that resolves wrapper-rendered or dynamic items.
function collectSeedOptions(children: ReactNode): ReadonlyMap<string, SelectOptionMetadata> {
  const seed = new Map<string, SelectOptionMetadata>();

  Children.forEach(children, (child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return;

    if (child.type === SelectItem) {
      const itemProps = child.props as SelectItemProps;
      seed.set(itemProps.value, {
        label: itemProps.textValue ?? getNodeText(itemProps.children) ?? itemProps.value,
        disabled: itemProps.disabled ?? false,
      });
      return;
    }

    for (const [value, metadata] of collectSeedOptions(child.props.children)) {
      seed.set(value, metadata);
    }
  });

  return seed;
}

"use client";

import { type AriaAttributes, createContext, type RefObject, useContext } from "react";

/** Metadata stored for select option. */
export interface SelectOptionMetadata {
  /** Accessible label text. */
  label: string;
  /** Disable the trigger and prevent open. */
  disabled: boolean;
}

/** Context value shared by select. */
export interface SelectContextValue {
  /** Controlled open state. Pair with onOpenChange. */
  open: boolean;
  /** Disable the trigger and prevent open. */
  disabled: boolean;
  /** searchable used by select. */
  searchable: boolean;
  /** Called when open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Controlled selected value. string[] when multiple, string in single mode. */
  value: string | null | string[];
  /** Enable multi-select. value/onChange become string[]. */
  multiple: boolean;
  /** search query used by select. */
  searchQuery: string;
  /** Called when search change occurs. */
  onSearchChange: (query: string) => void;
  /** Controlled highlighted item id. Pair with onHighlightChange. */
  highlighted: string | null;
  /** Updates highlighted. */
  setHighlighted: (value: string | null) => void;
  /** select item used by select. */
  selectItem: (value: string) => void;
  /** Registers option with select. */
  registerOption: (value: string, metadata: SelectOptionMetadata) => void;
  /** Unregisters option from select. */
  unregisterOption: (value: string) => void;
  /** options used by select. */
  options: ReadonlyMap<string, SelectOptionMetadata>;
  /** Ref for the trigger element. */
  triggerRef: RefObject<HTMLButtonElement | null>;
  /** Ref for the content element. */
  contentRef: RefObject<HTMLDivElement | null>;
  /** Ref for the search input element. */
  searchInputRef: RefObject<HTMLInputElement | null>;
  /**
   * Visual treatment. "card" renders the inline settings-panel layout (combine with
   * defaultOpen).
   */
  variant: "default" | "card";
  /** DOM id for listbox. */
  listboxId: string;
  /** DOM id for trigger. */
  triggerId: string;
  /** ARIA invalid used by select. */
  ariaInvalid: AriaAttributes["aria-invalid"] | undefined;
  /** ARIA described by used by select. */
  ariaDescribedBy: string | undefined;
  /** ARIA labelled by used by select. */
  ariaLabelledBy: string | undefined;
  /** Mark the select as required for native form validation. */
  required: boolean | undefined;
  /** Called when native invalid occurs. */
  onNativeInvalid: () => void;
}

/** React context backing select. */
export const SelectContext = createContext<SelectContextValue | undefined>(undefined);

/** Reads the select context. */
export function useSelectContext(source?: string): SelectContextValue {
  const context = useContext(SelectContext);
  if (!context) {
    throw new Error(`${source ?? "Select compound components"} must be used within a Select`);
  }
  return context;
}

import { isValidElement, type ReactNode } from "react";

/** Returns whether value selected. */
export function isValueSelected(value: string | null | string[], itemValue: string): boolean {
  return Array.isArray(value) ? value.includes(itemValue) : value === itemValue;
}

/** Returns node text. */
export function getNodeText(node: ReactNode): string | undefined {
  if (typeof node === "string" || typeof node === "number") return String(node);
  if (Array.isArray(node)) {
    const text = node.map(getNodeText).filter(Boolean).join("");
    return text || undefined;
  }
  if (isValidElement<{ children?: ReactNode }>(node)) return getNodeText(node.props.children);
  return undefined;
}

/** to selected array utility. */
export function toSelectedArray(value: string | null | string[], multiple: boolean): string[] {
  if (multiple) return Array.isArray(value) ? value : [];
  return value === null ? [] : [value as string];
}

/** to option id utility. */
export function toOptionId(listboxId: string, value: string): string {
  const encoded = Array.from(value, (char) => char.codePointAt(0)?.toString(36) ?? "0").join("-");
  return `${listboxId}-opt-${encoded || "empty"}`;
}

/** Returns whether active option visible. */
export function isActiveOptionVisible(
  options: ReadonlyMap<string, { label: string; disabled: boolean }>,
  value: string | null,
  searchQuery: string,
  matches: (label: string, query: string) => boolean,
): value is string {
  if (value === null) return false;
  const option = options.get(value);
  return !!option && !option.disabled && matches(option.label, searchQuery);
}

"use client";

import { cva } from "class-variance-authority";
import type { ComponentPropsWithRef, KeyboardEvent, ReactNode } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { mergeIds, resolveAriaInvalid } from "@/lib/aria";
import { matchesSearch } from "@/lib/search";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import { useSelectContext } from "./select-context";
import { isActiveOptionVisible, toOptionId } from "./selection";
import { useSelectTypeahead } from "./use-typeahead";
import { getVisibleEnabledOptions } from "./visible-options";

const selectTriggerVariants = cva(
  "flex items-center justify-between w-full px-3 py-2 text-sm font-mono cursor-pointer focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
  {
    variants: {
      variant: {
        default: "border border-border bg-background text-foreground hover:bg-secondary",
        card: "bg-foreground text-accent-foreground border-b border-foreground font-bold text-xs uppercase tracking-wider",
      },
    },
    defaultVariants: { variant: "default" },
  },
);

/** Props for select trigger. */
export interface SelectTriggerProps
  extends Omit<ComponentPropsWithRef<"button">, "children" | "type" | "disabled" | "id"> {
  /** Trigger label. Use SelectValue or SelectTags for selection display. */
  children: ReactNode;
  /** Custom trigger handle. Pass null to hide the default chevron. */
  handle?: ReactNode | null;
}

/** Button that opens/closes the dropdown. */
export function SelectTrigger({
  children,
  className,
  handle,
  "aria-label": ariaLabel,
  "aria-invalid": triggerAriaInvalid,
  "aria-labelledby": ariaLabelledByProp,
  "aria-describedby": ariaDescribedByProp,
  "aria-errormessage": ariaErrorMessage,
  ref,
  onClick,
  onKeyDown,
  ...props
}: SelectTriggerProps) {
  const {
    open,
    disabled,
    searchable,
    onOpenChange,
    triggerRef,
    variant,
    triggerId,
    listboxId,
    ariaInvalid,
    ariaDescribedBy,
    ariaLabelledBy,
    required,
    options,
    highlighted,
    searchQuery,
    setHighlighted,
  } = useSelectContext("SelectTrigger");
  const composedRef = useComposedRefs(triggerRef, ref);
  const handleTypeahead = useSelectTypeahead({ options, searchQuery, highlighted, setHighlighted });
  const resolvedAriaInvalid = resolveAriaInvalid(ariaInvalid ?? triggerAriaInvalid);
  const activeDescendant =
    open && !searchable && isActiveOptionVisible(options, highlighted, searchQuery, matchesSearch)
      ? toOptionId(listboxId, highlighted)
      : undefined;
  const composedDescribedBy = mergeIds(ariaDescribedByProp, ariaDescribedBy);
  const composedLabelledBy = ariaLabelledByProp ?? ariaLabelledBy;

  // APG closed-combobox table. The open listbox owns navigation/typeahead, so
  // these only apply while closed; the searchable trigger is a plain toggle (its
  // search input is the combobox), so Home/End/typeahead are skipped there.
  const highlightFirstOrLast = (edge: "first" | "last") => {
    const visible = getVisibleEnabledOptions(options, searchQuery);
    const target = edge === "first" ? visible[0] : visible.at(-1);
    if (target !== undefined) setHighlighted(target);
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLButtonElement>) => {
    onKeyDown?.(e);
    if (e.defaultPrevented) return;
    switch (e.key) {
      case "Enter":
      case " ":
        e.preventDefault();
        onOpenChange(!open);
        return;
      case "ArrowDown":
      case "ArrowUp":
        e.preventDefault();
        if (!open) onOpenChange(true);
        return;
    }

    if (open || searchable) return;

    if (e.key === "Home" || e.key === "End") {
      e.preventDefault();
      onOpenChange(true);
      highlightFirstOrLast(e.key === "Home" ? "first" : "last");
      return;
    }

    if (e.key.length === 1 && e.key !== " " && !e.ctrlKey && !e.metaKey && !e.altKey) {
      onOpenChange(true);
      handleTypeahead(e.key);
    }
  };

  return (
    // biome-ignore lint/a11y/useAriaPropsSupportedByRole: role is conditionally "combobox" (Biome cannot resolve the ternary); aria-activedescendant is applied in that same branch and is valid for the combobox role.
    <button
      {...props}
      ref={composedRef}
      id={triggerId}
      type="button"
      role={searchable ? undefined : "combobox"}
      data-slot="select-trigger"
      data-state={open ? "open" : "closed"}
      data-disabled={disabled ? "" : undefined}
      disabled={disabled}
      aria-label={ariaLabel}
      aria-labelledby={ariaLabel ? undefined : composedLabelledBy}
      aria-haspopup="listbox"
      aria-expanded={open}
      aria-controls={open && !searchable ? listboxId : undefined}
      aria-activedescendant={searchable ? undefined : activeDescendant}
      aria-required={required}
      aria-invalid={resolvedAriaInvalid}
      aria-describedby={composedDescribedBy}
      aria-errormessage={ariaErrorMessage}
      onClick={(event) => {
        onClick?.(event);
        if (!event.defaultPrevented) onOpenChange(!open);
      }}
      onKeyDown={handleKeyDown}
      className={cn(selectTriggerVariants({ variant }), className)}
    >
      {children}
      {handle !== null &&
        (handle ?? (
          <Chevron direction="down" size="sm" className="text-muted-foreground shrink-0" />
        ))}
    </button>
  );
}

"use client";

import {
  Children,
  isValidElement,
  type KeyboardEvent,
  type ReactNode,
  type Ref,
  type RefObject,
  useCallback,
  useEffectEvent,
  useLayoutEffect,
  useRef,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import type { FloatingAlign, FloatingSide } from "@/hooks/use-floating-position";
import { useNavigation } from "@/hooks/use-navigation";
import { matchesSearch } from "@/lib/search";
import { cn } from "@/lib/utils";
import { FloatingPanel } from "../floating-panel";
import { SearchableContent, type SearchableListboxProps } from "./searchable-content";
import type { SelectOptionMetadata } from "./select-context";
import { useSelectContext } from "./select-context";
import { SelectSearch } from "./select-search";
import { isActiveOptionVisible, toOptionId } from "./selection";
import { useSelectTypeahead } from "./use-typeahead";
import { getVisibleEnabledOptions } from "./visible-options";

function containsRefElement(ref: RefObject<HTMLElement | null>, target: Node | null): boolean {
  return target !== null && (ref.current?.contains(target) ?? false);
}

/** Props for select content. */
export interface SelectContentProps {
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Called when key down occurs. */
  onKeyDown?: (event: KeyboardEvent) => void;
  /** Side where the element appears. */
  side?: FloatingSide;
  /** Alignment relative to the anchor. */
  align?: FloatingAlign;
  /** side offset used by select content. */
  sideOffset?: number;
  /** collision padding used by select content. */
  collisionPadding?: number;
  /** portal container used by select content. */
  portalContainer?: Element | null;
  /** Live-region results-count text for searchable selects. Defaults to `${count} results`. */
  getResultsLabel?: (count: number) => string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
}

const SEARCH_INPUT_NAV_KEYS = new Set(["ArrowUp", "ArrowDown", "Enter"]);

/** Dropdown listbox with keyboard navigation. */
export function SelectContent({
  children,
  className,
  onKeyDown,
  side = "bottom",
  align = "start",
  // Tighter than FloatingPanel's default (6) so the dropdown reads as visually
  // attached to the trigger. Override per-instance via the prop.
  sideOffset = 4,
  collisionPadding = 8,
  portalContainer,
  getResultsLabel,
  ref,
}: SelectContentProps) {
  const {
    open,
    multiple,
    variant,
    value,
    highlighted,
    setHighlighted,
    onOpenChange,
    selectItem,
    listboxId,
    triggerId,
    searchInputRef,
    triggerRef,
    contentRef: selectContentRef,
    options,
    searchQuery,
    required,
    ariaInvalid,
  } = useSelectContext("SelectContent");
  const containerRef = useRef<HTMLDivElement>(null);
  const isDropdown = variant !== "card";
  const hasSearch = containsSelectSearchElement(children);
  const searchComposedRef = useComposedRefs(selectContentRef, ref);
  const fullComposedRef = useComposedRefs(containerRef, selectContentRef, ref);
  const composedRef = hasSearch ? searchComposedRef : fullComposedRef;

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "option",
    wrap: true,
    highlighted,
    onHighlightChange: setHighlighted,
    onSelect: selectItem,
    enabled: open,
    scopeToContainer: true,
  });

  // Bring a newly highlighted option into view for the non-arrow paths
  // (typeahead, searchable arrow nav). The arrow path inside useNavigation
  // already scrolls; these two end at setHighlighted, so without this an
  // off-screen active descendant stays invisible (the activedescendant
  // analogue of WCAG 2.4.11), mirroring use-listbox's typeahead scroll.
  const scrollOptionIntoView = useCallback(
    (optionValue: string) => {
      const node = containerRef.current?.ownerDocument.getElementById(
        toOptionId(listboxId, optionValue),
      );
      node?.scrollIntoView?.({ block: "nearest" });
    },
    [listboxId],
  );

  const setHighlightedAndScroll = useCallback(
    (optionValue: string) => {
      setHighlighted(optionValue);
      scrollOptionIntoView(optionValue);
    },
    [setHighlighted, scrollOptionIntoView],
  );

  const handleTypeahead = useSelectTypeahead({
    options,
    searchQuery,
    highlighted,
    setHighlighted: setHighlightedAndScroll,
  });

  function moveSearchHighlight(direction: 1 | -1): void {
    const visibleOptions = getVisibleEnabledOptions(options, searchQuery);
    if (visibleOptions.length === 0) return;

    const currentIndex = highlighted === null ? -1 : visibleOptions.indexOf(highlighted);
    let nextIndex = (currentIndex + direction + visibleOptions.length) % visibleOptions.length;
    if (currentIndex < 0) {
      nextIndex = direction > 0 ? 0 : visibleOptions.length - 1;
    }
    const nextOption = visibleOptions[nextIndex];
    if (nextOption === undefined) return;
    setHighlightedAndScroll(nextOption);
  }

  function handleSearchInputNavigation(e: KeyboardEvent): void {
    if (!SEARCH_INPUT_NAV_KEYS.has(e.key)) return;

    if (e.key === "Enter") {
      e.preventDefault();
      if (isActiveOptionVisible(options, highlighted, searchQuery, matchesSearch)) {
        selectItem(highlighted);
      }
      return;
    }

    e.preventDefault();
    moveSearchHighlight(e.key === "ArrowDown" ? 1 : -1);
  }

  const initHighlight = () => {
    if (highlighted !== null) return;
    let selectedValues: string[] = [];
    if (Array.isArray(value)) {
      selectedValues = value;
    } else if (value !== null) {
      selectedValues = [value];
    }
    const firstSelected = selectedValues[0];
    if (firstSelected !== undefined && !options.get(firstSelected)?.disabled) {
      setHighlighted(firstSelected);
      return;
    }
    for (const [itemValue, option] of options) {
      if (!option.disabled) {
        setHighlighted(itemValue);
        return;
      }
    }
  };

  // Read current highlight/value/options through an Effect Event so the focus +
  // init only runs on the open transition. Keying it to initHighlight's identity
  // re-fired on unrelated re-renders while open and re-stole focus from the user.
  const runOpenInit = useEffectEvent(() => {
    if (!searchInputRef.current) {
      containerRef.current?.focus();
    }
    initHighlight();
  });

  useLayoutEffect(() => {
    if (!open) return;
    runOpenInit();
  }, [open]);

  useLayoutEffect(() => {
    if (!open) return;

    const ownerDocument = containerRef.current?.ownerDocument ?? triggerRef.current?.ownerDocument;
    if (!ownerDocument) return;

    const handleDocumentKeyDown = (event: globalThis.KeyboardEvent) => {
      if (event.key !== "Escape") return;

      const NodeCtor = ownerDocument.defaultView?.Node;
      const targetNode = NodeCtor && event.target instanceof NodeCtor ? event.target : null;
      const targetIsInsideContent = containsRefElement(selectContentRef, targetNode);
      if (event.defaultPrevented && targetIsInsideContent) return;

      event.preventDefault();
      onOpenChange(false);
      triggerRef.current?.focus();
    };

    ownerDocument.addEventListener("keydown", handleDocumentKeyDown);
    return () => ownerDocument.removeEventListener("keydown", handleDocumentKeyDown);
  }, [open, onOpenChange, selectContentRef, triggerRef]);

  const handleKeyDown = (e: KeyboardEvent) => {
    onKeyDown?.(e);
    if (e.defaultPrevented) return;

    if (e.key === "Escape") {
      e.preventDefault();
      onOpenChange(false);
      triggerRef.current?.focus();
      return;
    }

    if (e.key === "Tab") {
      if (highlighted !== null && !multiple) selectItem(highlighted);
      onOpenChange(false);
      // Restore focus to the trigger synchronously (mirroring the Escape branch)
      // for every mode — multiple and searchable null-highlight never run the
      // single-select commit that refocuses, so without this Tab would leave
      // focus in the portaled panel and drop to the end of <body>. The default
      // Tab action then advances from the trigger to the next element.
      triggerRef.current?.focus();
      return;
    }

    const isTyping = e.target === searchInputRef.current;
    if (isTyping) {
      handleSearchInputNavigation(e);
      return;
    }

    const isModified = e.ctrlKey || e.metaKey || e.altKey;
    // Space extends an in-progress typeahead query (e.g. "new y") instead of
    // selecting: run typeahead first for Space so a non-empty buffer suppresses
    // the Space-select that navKeyDown would otherwise dispatch.
    if (e.key === " " && !isModified && handleTypeahead(e.key)) return;
    navKeyDown(e);
    if (e.key !== " " && !isModified) handleTypeahead(e.key);
  };

  const activeDescendant = isActiveOptionVisible(options, highlighted, searchQuery, matchesSearch)
    ? toOptionId(listboxId, highlighted)
    : undefined;
  const listboxPropsBase = {
    id: listboxId,
    role: "listbox" as const,
    tabIndex: -1,
    "aria-multiselectable": multiple || undefined,
    "aria-activedescendant": !hasSearch ? activeDescendant : undefined,
    "aria-labelledby": triggerId,
    "aria-required": required,
    "aria-invalid": ariaInvalid,
  } satisfies SearchableListboxProps;
  const listboxProps = hasSearch
    ? listboxPropsBase
    : { ...listboxPropsBase, onKeyDown: handleKeyDown };
  const contentBody = hasSearch ? (
    <SearchableContent listboxProps={listboxProps} ref={containerRef}>
      {children}
    </SearchableContent>
  ) : (
    children
  );

  if (!isDropdown) {
    return (
      <div
        {...(hasSearch ? { onKeyDown: handleKeyDown } : listboxProps)}
        ref={composedRef}
        hidden={!open}
        className={cn("w-full overflow-hidden p-1 space-y-0.5 outline-none", className)}
      >
        {contentBody}
        {hasSearch && (
          <MatchCount
            options={options}
            searchQuery={searchQuery}
            getResultsLabel={getResultsLabel}
          />
        )}
      </div>
    );
  }

  return (
    <FloatingPanel
      {...(hasSearch ? { onKeyDown: handleKeyDown } : listboxProps)}
      open={open}
      triggerRef={triggerRef}
      portalContainer={portalContainer}
      side={side}
      align={align}
      sideOffset={sideOffset}
      collisionPadding={collisionPadding}
      avoidCollisions
      matchTriggerWidth
      ref={composedRef}
      className={cn(
        "border border-border bg-background shadow-2xl rounded-sm overflow-y-auto outline-none",
        className,
      )}
      // Cap the dropdown to the room FloatingPanel reports and scroll long lists
      // instead of overflowing the viewport (the var is set on this element).
      style={{
        width: "var(--ui-floating-trigger-width)",
        maxHeight: "var(--floating-panel-available-height)",
      }}
    >
      {contentBody}
      {hasSearch && (
        <MatchCount options={options} searchQuery={searchQuery} getResultsLabel={getResultsLabel} />
      )}
    </FloatingPanel>
  );
}

function containsSelectSearchElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (isSelectSearchElement(child)) return true;
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    return containsSelectSearchElement(child.props.children);
  });
}

function isSelectSearchElement(child: ReactNode): boolean {
  return isValidElement(child) && child.type === SelectSearch;
}

function MatchCount({
  options,
  searchQuery,
  getResultsLabel,
}: {
  options: ReadonlyMap<string, SelectOptionMetadata>;
  searchQuery: string;
  getResultsLabel?: (count: number) => string;
}) {
  // Mount the live region unconditionally (empty until a query exists) so it is
  // present in the DOM before its first announcement — a region that enters the
  // DOM already containing text is often not announced by SR/browser pairs.
  let count = 0;
  for (const option of options.values()) {
    if (matchesSearch(option.label, searchQuery)) count++;
  }
  return (
    // biome-ignore lint/a11y/useSemanticElements: role="status" is the sr-only results-count live region; <output> carries form-association semantics that do not fit here.
    <div role="status" aria-live="polite" className="sr-only">
      {searchQuery ? (getResultsLabel?.(count) ?? `${count} results`) : ""}
    </div>
  );
}

import { matchesSearch } from "@/lib/search";
import type { SelectOptionMetadata } from "./select-context";

/** Returns visible enabled option entries. */
export function getVisibleEnabledOptionEntries(
  options: ReadonlyMap<string, SelectOptionMetadata>,
  searchQuery: string,
): Array<[string, SelectOptionMetadata]> {
  const entries: Array<[string, SelectOptionMetadata]> = [];
  for (const [itemValue, option] of options) {
    if (!option.disabled && matchesSearch(option.label, searchQuery)) {
      entries.push([itemValue, option]);
    }
  }
  return entries;
}

/** Options for get visible enabled. */
export function getVisibleEnabledOptions(
  options: ReadonlyMap<string, SelectOptionMetadata>,
  searchQuery: string,
): string[] {
  return getVisibleEnabledOptionEntries(options, searchQuery).map(([itemValue]) => itemValue);
}

"use client";

import { useTypeaheadBuffer } from "@/hooks/use-typeahead-buffer";
import { typeaheadSearch } from "@/lib/typeahead";
import type { SelectOptionMetadata } from "./select-context";
import { getVisibleEnabledOptionEntries } from "./visible-options";

/** Options for use select typeahead. */
interface UseSelectTypeaheadOptions {
  /** options used by use select typeahead. */
  options: ReadonlyMap<string, SelectOptionMetadata>;
  /** search query used by use select typeahead. */
  searchQuery: string;
  /** Controlled highlighted item id. Pair with onHighlightChange. */
  highlighted: string | null;
  /** Updates highlighted. */
  setHighlighted: (value: string) => void;
}

/** Provides select typeahead behavior. */
export function useSelectTypeahead({
  options,
  searchQuery,
  highlighted,
  setHighlighted,
}: UseSelectTypeaheadOptions) {
  const readTypeaheadQuery = useTypeaheadBuffer();

  // Returns true when the key was buffered into the typeahead query so callers
  // can suppress a competing Space-select for the same keystroke.
  return function handleTypeahead(key: string): boolean {
    const query = readTypeaheadQuery(key);
    if (query === null) return false;

    const visibleOptions = getVisibleEnabledOptionEntries(options, searchQuery);
    if (visibleOptions.length === 0) return true;

    const currentIndex =
      highlighted === null
        ? -1
        : visibleOptions.findIndex(([itemValue]) => itemValue === highlighted);

    const match = typeaheadSearch({
      items: visibleOptions,
      query,
      currentIndex,
      getLabel: ([, option]) => option.label,
    });

    if (match) setHighlighted(match[0]);
    return true;
  };
}

"use client";

import {
  type AriaAttributes,
  Children,
  cloneElement,
  Fragment,
  isValidElement,
  type KeyboardEvent,
  type ReactNode,
  type Ref,
} from "react";
import { SelectEmpty } from "./select-empty";
import { SelectSearch, type SelectSearchProps } from "./select-search";

/** Props for listbox. */
type ListboxProps = {
  /** ID applied to the rendered element. */
  id: string;
  /** ARIA role applied to the rendered element. */
  role: "listbox";
  /** Tab index applied to the rendered element. */
  tabIndex: -1;
  /** ARIA multiselectable state forwarded to the rendered element. */
  "aria-multiselectable": boolean | undefined;
  /** ID of the active descendant for composite focus. */
  "aria-activedescendant": string | undefined;
  /** ID of the element that labels this component. */
  "aria-labelledby": string;
  /** ARIA required state forwarded to the rendered element. */
  "aria-required": boolean | undefined;
  /** ARIA invalid state forwarded to the rendered control. */
  "aria-invalid": AriaAttributes["aria-invalid"] | undefined;
  /** Called when key down occurs. */
  onKeyDown?: (event: KeyboardEvent<HTMLDivElement>) => void;
};

/** Props for searchable listbox. */
export type SearchableListboxProps = Omit<ListboxProps, "onKeyDown">;

/**
 * Dropdown select with search, multiple selection, card variant, and controlled keyboard
 * integration points. 8 composable parts.
 */
export function SearchableContent({
  children,
  listboxProps,
  ref,
}: {
  children: ReactNode;
  listboxProps: SearchableListboxProps;
  ref: Ref<HTMLDivElement>;
}) {
  const { searchChildren, optionChildren, emptyChildren } = partitionSelectSearchChildren(children);
  // Order the search row by its position prop: "top" renders it before the
  // listbox, "bottom" (default) after — matching the documented placement and
  // the border compoundVariants in select-search.tsx.
  const searchAtTop = getSearchPosition(searchChildren) === "top";

  const listbox = (
    <div {...listboxProps} ref={ref} className="p-1 space-y-0.5 outline-none">
      {optionChildren}
    </div>
  );

  return (
    <>
      {searchAtTop && searchChildren}
      {listbox}
      {emptyChildren}
      {!searchAtTop && searchChildren}
    </>
  );
}

function getSearchPosition(searchChildren: ReactNode[]): "top" | "bottom" {
  const search = searchChildren.find((child) =>
    isValidElement<SelectSearchProps>(child),
  ) as ReactNode;
  if (isValidElement<SelectSearchProps>(search)) {
    return search.props.position ?? "bottom";
  }
  return "bottom";
}

function isSelectSearchElement(child: ReactNode): boolean {
  return isValidElement(child) && child.type === SelectSearch;
}

function isSelectEmptyElement(child: ReactNode): boolean {
  return isValidElement(child) && child.type === SelectEmpty;
}

function partitionSelectSearchChildren(children: ReactNode): {
  searchChildren: ReactNode[];
  optionChildren: ReactNode[];
  emptyChildren: ReactNode[];
} {
  const searchChildren: ReactNode[] = [];
  const optionChildren: ReactNode[] = [];
  const emptyChildren: ReactNode[] = [];

  Children.forEach(children, (child) => {
    if (isSelectSearchElement(child)) {
      searchChildren.push(child);
      return;
    }

    if (isSelectEmptyElement(child)) {
      emptyChildren.push(child);
      return;
    }

    if (
      !isValidElement<{ children?: ReactNode }>(child) ||
      !containsPartitionedSelectElement(child.props.children)
    ) {
      optionChildren.push(child);
      return;
    }

    const nested = partitionSelectSearchChildren(child.props.children);
    searchChildren.push(...nested.searchChildren);
    emptyChildren.push(...nested.emptyChildren);
    if (nested.optionChildren.length === 0) return;

    if (child.type === Fragment) {
      optionChildren.push(...nested.optionChildren);
    } else {
      optionChildren.push(cloneElement(child, undefined, nested.optionChildren));
    }
  });

  return { searchChildren, optionChildren, emptyChildren };
}

function containsPartitionedSelectElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (isSelectSearchElement(child) || isSelectEmptyElement(child)) return true;
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    return containsPartitionedSelectElement(child.props.children);
  });
}

"use client";

import { cva } from "class-variance-authority";
import {
  type ComponentPropsWithRef,
  type MouseEvent,
  type ReactNode,
  useLayoutEffect,
} from "react";
import { matchesSearch } from "@/lib/search";
import { cn } from "@/lib/utils";
import { OverflowText } from "../overflow/overflow-text";
import { useSelectContext } from "./select-context";
import { getNodeText, isValueSelected, toOptionId } from "./selection";

const NBSP = "\u00a0";
const BULLET = "\u25cf";
const CHECKMARK = "\u2713";

const selectItemVariants = cva(
  "flex items-center gap-2 px-2 py-1.5 text-sm font-mono cursor-pointer",
  {
    variants: {
      state: {
        default: "text-foreground/60",
        highlighted: "bg-secondary text-foreground",
        selected: "bg-foreground text-background font-medium",
        selectedMulti: "text-foreground",
        selectedMultiHighlighted: "bg-secondary text-foreground",
      },
      variant: {
        default: "",
        card: "",
      },
    },
    compoundVariants: [
      {
        variant: "card",
        state: ["default", "selectedMulti"],
        className: "text-muted-foreground hover:bg-border/30",
      },
      { variant: "card", state: "highlighted", className: "text-muted-foreground bg-border/30" },
      {
        variant: "card",
        state: ["selected", "selectedMultiHighlighted"],
        className: "bg-muted-foreground text-background font-medium",
      },
    ],
    defaultVariants: { state: "default", variant: "default" },
  },
);

/** Allowed item state values. */
type ItemState =
  | "default"
  | "highlighted"
  | "selected"
  | "selectedMulti"
  | "selectedMultiHighlighted";

function getItemState(isSelected: boolean, isHighlighted: boolean, multiple: boolean): ItemState {
  if (!isSelected) return isHighlighted ? "highlighted" : "default";
  if (multiple) return isHighlighted ? "selectedMultiHighlighted" : "selectedMulti";
  return "selected";
}

/**
 * Dropdown select with search, multiple selection, card variant, and controlled keyboard
 * integration points. 8 composable parts.
 */
export type SelectItemIndicator = "auto" | "checkbox" | "radio" | "none";

/** Props for select item. */
export interface SelectItemProps<TValue extends string = string>
  extends Omit<ComponentPropsWithRef<"div">, "children" | "onSelect"> {
  /** Item value. Must be unique within the Select. */
  value: TValue;
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Disable the option. */
  disabled?: boolean;
  /**
   * Selection indicator style. "auto" picks checkbox in multi mode and a check mark in single
   * mode.
   */
  indicator?: SelectItemIndicator;
  /** Override the searchable/typeahead text when children are not plain text. */
  textValue?: string;
}

function renderIndicator(
  mode: SelectItemIndicator,
  isSelected: boolean,
  isMultiple: boolean,
): string | null {
  if (mode === "none") return null;
  if (mode === "checkbox" || (mode === "auto" && isMultiple)) {
    return isSelected ? "[x]" : "[ ]";
  }
  if (mode === "radio") {
    return isSelected ? `[${NBSP}${BULLET}${NBSP}]` : `[${NBSP}${NBSP}${NBSP}]`;
  }
  return isSelected ? CHECKMARK : null;
}

/**
 * Selectable option. indicator prop: auto/checkbox/radio/none. textValue prop for custom search
 * text.
 */
export function SelectItem<TValue extends string = string>({
  value: itemValue,
  children,
  disabled = false,
  indicator = "auto",
  textValue,
  className,
  ref,
  onClick,
  onMouseEnter,
  ...props
}: SelectItemProps<TValue>) {
  const {
    value,
    open,
    multiple,
    highlighted,
    searchQuery,
    selectItem,
    registerOption,
    unregisterOption,
    options,
    variant,
    listboxId,
  } = useSelectContext("SelectItem");

  // One derivation for registration and the visibility filter: textValue wins,
  // then the flattened node text (icon + text JSX), then the raw value.
  const label = textValue ?? getNodeText(children) ?? itemValue;

  useLayoutEffect(() => {
    registerOption(itemValue, { label, disabled });
    return () => unregisterOption(itemValue);
  }, [registerOption, unregisterOption, itemValue, label, disabled]);

  const isSelected = isValueSelected(value, itemValue);

  // Read the registered label so the filter matches the same text the metadata
  // (typeahead, match count, active descendant) uses; fall back to the local
  // derivation on the first render before registration commits.
  const filterLabel = options.get(itemValue)?.label ?? label;

  if (!open) return null;
  if (!matchesSearch(filterLabel, searchQuery)) return null;

  const isHighlighted = !disabled && highlighted === itemValue;
  const state = getItemState(isSelected, isHighlighted, multiple);
  const indicatorText = renderIndicator(indicator, isSelected, multiple);
  const showIndicatorSlot = indicator !== "none";

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (!event.defaultPrevented && !disabled) selectItem(itemValue);
  };

  return (
    // biome-ignore lint/a11y/useFocusableInteractive: WAI-ARIA listbox pattern — option stays non-focusable while the listbox container holds focus and aria-activedescendant tracks the active option.
    // biome-ignore lint/a11y/useKeyWithClickEvents: Enter/Space selection is handled centrally by the select listbox, not per option.
    <div
      {...props}
      ref={ref}
      id={toOptionId(listboxId, itemValue)}
      role="option"
      aria-selected={isSelected}
      aria-disabled={disabled || undefined}
      data-value={itemValue}
      data-label={label}
      data-highlighted={isHighlighted ? "" : undefined}
      onClick={handleClick}
      onMouseEnter={onMouseEnter}
      className={cn(
        selectItemVariants({ state, variant }),
        disabled && "opacity-50 cursor-not-allowed",
        className,
      )}
    >
      {showIndicatorSlot && (
        <span
          aria-hidden="true"
          className={cn(
            "font-mono shrink-0 whitespace-nowrap min-w-[3ch]",
            !indicatorText && "invisible",
          )}
        >
          {indicatorText ?? CHECKMARK}
        </span>
      )}
      {typeof children === "string" ? (
        <OverflowText className="flex-1 min-w-0">{children}</OverflowText>
      ) : (
        // Non-string children skip OverflowText (which requires `children: string`);
        // consumers using JSX labels should ensure their items fit or wrap manually.
        <span className="flex-1 min-w-0 truncate">{children}</span>
      )}
      {variant === "card" && isHighlighted && isSelected && (
        <span aria-hidden="true" className="ml-auto text-2xs motion-safe:animate-pulse">
          &lt;
        </span>
      )}
    </div>
  );
}

"use client";

import { cva } from "class-variance-authority";
import { useLayoutEffect } from "react";
import { matchesSearch } from "@/lib/search";
import { cn } from "@/lib/utils";
import { useSelectContext } from "./select-context";
import { isActiveOptionVisible, toOptionId } from "./selection";

/** Props for select search. */
export interface SelectSearchProps {
  /** Placeholder shown when no value is present. */
  placeholder?: string;
  /**
   * Where the search row renders relative to the option list. "bottom" (default) renders it
   * below the list with a top border; "top" renders it above with a bottom border.
   */
  position?: "top" | "bottom";
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Accessible name when no visible label is supplied. */
  "aria-label"?: string;
}

const selectSearchVariants = cva("flex items-center gap-2 px-3 py-2", {
  variants: {
    variant: {
      default: "",
      card: "border-b border-foreground",
    },
    position: {
      top: "",
      bottom: "",
    },
  },
  compoundVariants: [
    { variant: "default", position: "top", className: "border-b border-border" },
    { variant: "default", position: "bottom", className: "border-t border-border" },
  ],
  defaultVariants: { variant: "default", position: "bottom" },
});

/**
 * Filter input. position='bottom' (default) renders it below the option list; position='top'
 * renders it above.
 */
export function SelectSearch({
  placeholder = "Search...",
  position = "bottom",
  className,
  "aria-label": ariaLabel,
}: SelectSearchProps) {
  const {
    open,
    searchQuery,
    onSearchChange,
    variant,
    searchInputRef,
    ariaInvalid,
    ariaLabelledBy,
    required,
    options,
    highlighted,
    listboxId,
  } = useSelectContext("SelectSearch");
  const activeDescendant = isActiveOptionVisible(options, highlighted, searchQuery, matchesSearch)
    ? toOptionId(listboxId, highlighted)
    : undefined;

  useLayoutEffect(() => {
    if (open) searchInputRef.current?.focus();
  }, [open, searchInputRef]);

  if (!open) return null;

  return (
    <div className={selectSearchVariants({ variant, position })}>
      <span className="text-foreground/50 text-sm font-mono shrink-0">&gt;</span>
      <input
        ref={searchInputRef}
        type="search"
        role="combobox"
        aria-labelledby={ariaLabelledBy || undefined}
        aria-label={ariaLabelledBy ? undefined : (ariaLabel ?? "Search options")}
        aria-controls={listboxId}
        aria-expanded={open}
        aria-activedescendant={activeDescendant}
        aria-autocomplete="list"
        aria-required={required}
        aria-invalid={ariaInvalid}
        value={searchQuery}
        onChange={(e) => onSearchChange(e.target.value)}
        placeholder={placeholder}
        className={cn(
          "text-sm bg-transparent text-foreground w-full outline-none font-mono placeholder:text-foreground/55",
          className,
        )}
      />
    </div>
  );
}

"use client";

import { cva } from "class-variance-authority";
import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { type SelectOptionMetadata, useSelectContext } from "./select-context";
import { toSelectedArray } from "./selection";

const selectValuePlaceholderVariants = cva("", {
  variants: {
    variant: {
      // 55% keeps placeholder text at >=4.5:1 (WCAG AA) on --background.
      default: "text-foreground/55",
      card: "text-accent-foreground/55",
    },
  },
  defaultVariants: { variant: "default" },
});

/**
 * Dropdown select with search, multiple selection, card variant, and controlled keyboard
 * integration points. 8 composable parts.
 */
export type SelectValueDisplay = "count" | "list" | "truncate";

/** Props for select value render. */
export interface SelectValueRenderProps {
  /** Marks the item as selected. */
  selected: string[];
  /** labels used by select value. */
  labels: ReadonlyMap<string, string>;
}

function getLabelMap(
  options: ReadonlyMap<string, SelectOptionMetadata>,
): ReadonlyMap<string, string> {
  return new Map(Array.from(options, ([value, option]) => [value, option.label]));
}

/** Props for select value. */
export interface SelectValueProps {
  /** Rendered when nothing is selected. */
  placeholder?: ReactNode;
  /**
   * Multi-select display mode. "count" shows N selected, "list" comma-separates, "truncate"
   * shows first N + "+M more".
   */
  display?: SelectValueDisplay;
  /** Number of items shown before "+N more" when display="truncate". */
  truncateAfter?: number;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /**
   * Render function for fully custom selection display. Example: selected.map((value) =>
   * labels.get(value) ?? value).join(', ').
   */
  children?: ((props: SelectValueRenderProps) => ReactNode) | ReactNode;
  /** "N selected" summary text (count display). Defaults to `${count} selected`. */
  getSelectedLabel?: (count: number) => string;
  /** "+N more" overflow text (truncate display). Defaults to ` +${count} more`. */
  getOverflowLabel?: (count: number) => string;
}

function MultiValue({
  selected,
  options,
  display,
  truncateAfter,
  getSelectedLabel,
  getOverflowLabel,
}: {
  selected: string[];
  options: ReadonlyMap<string, SelectOptionMetadata>;
  display: SelectValueDisplay;
  truncateAfter: number;
  getSelectedLabel?: (count: number) => string;
  getOverflowLabel?: (count: number) => string;
}): ReactNode {
  if (selected.length === 1) {
    const firstSelected = selected[0];
    return firstSelected === undefined ? null : (
      <span>{options.get(firstSelected)?.label ?? firstSelected}</span>
    );
  }

  const labels = selected.map((v) => options.get(v)?.label ?? v);

  switch (display) {
    case "list":
      return <span>{labels.join(", ")}</span>;

    case "truncate": {
      const visible = labels.slice(0, truncateAfter);
      const overflow = labels.length - truncateAfter;
      return (
        <span>
          {visible.join(", ")}
          {overflow > 0 && (getOverflowLabel?.(overflow) ?? ` +${overflow} more`)}
        </span>
      );
    }

    default:
      return <span>{getSelectedLabel?.(selected.length) ?? `${selected.length} selected`}</span>;
  }
}

/**
 * Displays selected value or placeholder. Props: display (count|list|truncate), truncateAfter,
 * children as render function.
 */
export function SelectValue({
  placeholder = "Select...",
  display = "count",
  truncateAfter = 2,
  className,
  children,
  getSelectedLabel,
  getOverflowLabel,
}: SelectValueProps) {
  const { value, multiple, options, variant } = useSelectContext("SelectValue");

  const selected = toSelectedArray(value, multiple);
  // Treat "" as unset unless the consumer explicitly registers an option with value="".
  const isUnsetEmptyString =
    !multiple && selected.length === 1 && selected[0] === "" && !options.has("");

  if (selected.length === 0 || isUnsetEmptyString) {
    return (
      <span className={cn(selectValuePlaceholderVariants({ variant }), className)}>
        {placeholder}
      </span>
    );
  }

  if (typeof children === "function") {
    return (
      <span className={className}>{children({ selected, labels: getLabelMap(options) })}</span>
    );
  }

  return (
    <span className={className}>
      <MultiValue
        selected={selected}
        options={options}
        display={display}
        truncateAfter={truncateAfter}
        getSelectedLabel={getSelectedLabel}
        getOverflowLabel={getOverflowLabel}
      />
    </span>
  );
}

"use client";

import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useSelectContext } from "./select-context";
import { toSelectedArray } from "./selection";

const selectTagsPlaceholderVariants = cva("", {
  variants: {
    variant: {
      default: "text-foreground/55",
      card: "text-accent-foreground/55",
    },
  },
  defaultVariants: { variant: "default" },
});

/** Props for select tags. */
export interface SelectTagsProps {
  /** Rendered when nothing is selected. Only available in multi-select mode. */
  placeholder?: string;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

/** Displays selected items as outlined chips (multiple select) */
export function SelectTags({ placeholder = "Select...", className }: SelectTagsProps) {
  const { value, multiple, options, variant } = useSelectContext("SelectTags");

  if (!multiple) return null;

  const selected = toSelectedArray(value, multiple);

  if (selected.length === 0) {
    return <span className={selectTagsPlaceholderVariants({ variant })}>{placeholder}</span>;
  }

  return (
    <span className={cn("flex flex-wrap gap-1 flex-1 min-w-0", className)}>
      {selected.map((v) => {
        const label = options.get(v)?.label ?? v;
        return (
          <span
            key={v}
            className="inline-flex items-center gap-0.5 font-mono text-xs border border-foreground/40 px-1 text-foreground whitespace-nowrap"
          >
            {label}
          </span>
        );
      })}
    </span>
  );
}

"use client";

import type { ReactNode } from "react";
import { matchesSearch } from "@/lib/search";
import { cn } from "@/lib/utils";
import { type SelectOptionMetadata, useSelectContext } from "./select-context";

/** Props for select empty. */
export interface SelectEmptyProps {
  /** Custom empty-state content. */
  children?: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

/** Shows '> no results.' when no items match the search query. Accepts children. */
export function SelectEmpty({ children, className }: SelectEmptyProps) {
  const { searchQuery, options } = useSelectContext("SelectEmpty");

  if (!searchQuery || hasMatch(options, searchQuery)) return null;

  return (
    <div className={cn("px-3 py-4 text-sm font-mono text-muted-foreground", className)}>
      {children ?? "> no results."}
    </div>
  );
}

function hasMatch(labels: ReadonlyMap<string, SelectOptionMetadata>, query: string): boolean {
  for (const option of labels.values()) {
    if (matchesSearch(option.label, query)) return true;
  }
  return false;
}

"use client";

import {
  type AriaAttributes,
  type RefObject,
  useCallback,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useFormReset } from "@/hooks/use-form-reset";
import { useOutsideClick } from "@/hooks/use-outside-click";
import { matchesSearch } from "@/lib/search";
import type { SelectContextValue, SelectOptionMetadata } from "./select-context";

type SelectValue = string | null | string[];

/** Options for use select state base. */
interface UseSelectStateBaseOptions {
  /** Controlled open state. Pair with onOpenChange. */
  open?: boolean;
  /** open controlled used by use select state base. */
  openControlled?: boolean;
  /** Called when open state changes. */
  onOpenChange?: (open: boolean) => void;
  /**
   * Initial open state for uncontrolled usage. Useful with variant="card" for a settings-panel
   * layout that renders its list immediately.
   */
  defaultOpen?: boolean;
  /** Controlled highlighted item id. Pair with onHighlightChange. */
  highlighted?: string | null;
  /** highlighted controlled used by use select state base. */
  highlightedControlled?: boolean;
  /** Called when the highlighted item changes via keyboard or search. */
  onHighlightChange?: (value: string | null) => void;
  /** Disable the trigger and prevent open. */
  disabled?: boolean;
  /** searchable used by use select state base. */
  searchable?: boolean;
  /**
   * Visual treatment. "card" renders the inline settings-panel layout (combine with
   * defaultOpen).
   */
  variant?: "default" | "card";
  /** ARIA invalid used by use select state base. */
  ariaInvalid?: AriaAttributes["aria-invalid"];
  /** ARIA described by used by use select state base. */
  ariaDescribedBy?: string;
  /** ARIA labelled by used by use select state base. */
  ariaLabelledBy?: string;
  /** trigger id prop used by use select state base. */
  triggerIdProp?: string;
  /** Mark the select as required for native form validation. */
  required?: boolean;
  /** seed options used by use select state base. */
  seedOptions: ReadonlyMap<string, SelectOptionMetadata>;
}

/** Options for use select state single. */
interface UseSelectStateSingleOptions extends UseSelectStateBaseOptions {
  /** Enable multi-select. value/onChange become string[]. */
  multiple?: false;
  /** Controlled selected value. string[] when multiple, string in single mode. */
  value?: string;
  /** value controlled used by use select state single. */
  valueControlled?: boolean;
  /** Called when the selection changes. */
  onChange?: (value: string) => void;
  /** Initial selected value for uncontrolled usage. */
  defaultValue?: string;
}

/** Options for use select state multiple. */
interface UseSelectStateMultipleOptions extends UseSelectStateBaseOptions {
  /** Enable multi-select. value/onChange become string[]. */
  multiple: true;
  /** Controlled selected value. string[] when multiple, string in single mode. */
  value?: string[];
  /** value controlled used by use select state multiple. */
  valueControlled?: boolean;
  /** Called when the selection changes. */
  onChange?: (value: string[]) => void;
  /** Initial selected value for uncontrolled usage. */
  defaultValue?: string[];
}

/** Options for use select state. */
export type UseSelectStateOptions = UseSelectStateSingleOptions | UseSelectStateMultipleOptions;

/** Return value from use select state. */
export interface UseSelectStateReturn {
  /** context value. */
  contextValue: SelectContextValue;
  /** Ref for the wrapper element. */
  wrapperRef: RefObject<HTMLDivElement | null>;
}

function getDefaultSelectValue(
  multiple: boolean,
  defaultValue: SelectValue | undefined,
): SelectValue {
  return defaultValue ?? (multiple ? [] : null);
}

/** Provides select state behavior. */
export function useSelectState(options: UseSelectStateOptions): UseSelectStateReturn {
  const {
    open: controlledOpen,
    openControlled,
    onOpenChange,
    defaultOpen = false,
    value: controlledValue,
    valueControlled,
    defaultValue,
    highlighted: controlledHighlighted,
    highlightedControlled,
    onHighlightChange,
    multiple = false,
    disabled = false,
    searchable = false,
    variant = "default",
    ariaInvalid,
    ariaDescribedBy,
    ariaLabelledBy,
    triggerIdProp,
    required,
    seedOptions,
  } = options;
  const [registeredOptions, setRegisteredOptions] = useState<
    ReadonlyMap<string, SelectOptionMetadata>
  >(() => new Map());
  const registerOption = useCallback((itemValue: string, metadata: SelectOptionMetadata) => {
    setRegisteredOptions((current) => {
      const existing = current.get(itemValue);
      if (
        existing &&
        existing.label === metadata.label &&
        existing.disabled === metadata.disabled
      ) {
        return current;
      }
      const next = new Map(current);
      next.set(itemValue, metadata);
      return next;
    });
  }, []);
  const unregisterOption = useCallback((itemValue: string) => {
    setRegisteredOptions((current) => {
      if (!current.has(itemValue)) return current;
      const next = new Map(current);
      next.delete(itemValue);
      return next;
    });
  }, []);
  // Mounted items (registration) are authoritative; the static seed only fills
  // labels for direct-child items while the dropdown is closed and unmounted.
  const optionMetadata = useMemo<ReadonlyMap<string, SelectOptionMetadata>>(() => {
    if (registeredOptions.size === 0) return seedOptions;
    const merged = new Map(seedOptions);
    for (const [value, metadata] of registeredOptions) merged.set(value, metadata);
    return merged;
  }, [registeredOptions, seedOptions]);
  const resetValue = getDefaultSelectValue(multiple, defaultValue);
  const onSingleChange = options.multiple ? undefined : options.onChange;
  const onMultipleChange = options.multiple ? options.onChange : undefined;
  const valueChangeHandler = (nextValue: SelectValue) => {
    if (multiple) {
      if (Array.isArray(nextValue)) onMultipleChange?.(nextValue);
      return;
    }
    if (typeof nextValue === "string") onSingleChange?.(nextValue);
  };
  const isOpenControlled = openControlled ?? controlledOpen !== undefined;
  const isValueControlled = valueControlled ?? controlledValue !== undefined;
  const isHighlightedControlled = highlightedControlled ?? controlledHighlighted !== undefined;

  const [isOpen, setIsOpen] = useControllableState<boolean>({
    value: isOpenControlled ? (controlledOpen ?? false) : controlledOpen,
    controlled: isOpenControlled,
    defaultValue: defaultOpen,
    onChange: onOpenChange,
  });
  const [value, setValue] = useControllableState<SelectValue>({
    value: isValueControlled ? (controlledValue ?? resetValue) : controlledValue,
    controlled: isValueControlled,
    defaultValue: resetValue,
    onChange: valueChangeHandler,
  });
  const [searchQuery, setSearchQuery] = useState("");
  const [nativeInvalid, setNativeInvalid] = useState(false);
  const [highlighted, setHighlighted] = useControllableState<string | null>({
    value: isHighlightedControlled ? (controlledHighlighted ?? null) : controlledHighlighted,
    controlled: isHighlightedControlled,
    defaultValue: null,
    onChange: onHighlightChange,
  });

  const triggerRef = useRef<HTMLButtonElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const listboxId = useId();

  // Stable ref required: dep of the contextValue memo and of selectItem below.
  const handleOpenChange = useCallback(
    (open: boolean) => {
      if (disabled) return;
      setIsOpen(open);
      if (!open) {
        setSearchQuery("");
        setHighlighted(null);
      }
    },
    [disabled, setIsOpen, setHighlighted],
  );

  useOutsideClick(wrapperRef, () => handleOpenChange(false), isOpen, [contentRef]);

  // Stable ref required: dep of the contextValue memo below.
  const onSearchChange = useCallback(
    (query: string) => {
      setSearchQuery(query);
      const highlightedOption = highlighted === null ? undefined : optionMetadata.get(highlighted);
      if (
        highlightedOption &&
        !highlightedOption.disabled &&
        matchesSearch(highlightedOption.label, query)
      ) {
        return;
      }

      for (const [itemValue, option] of optionMetadata) {
        if (!option.disabled && matchesSearch(option.label, query)) {
          setHighlighted(itemValue);
          return;
        }
      }

      setHighlighted(null);
    },
    [highlighted, optionMetadata, setHighlighted],
  );

  // Stable ref required: dep of the contextValue memo below.
  const selectItem = useCallback(
    (itemValue: string) => {
      const option = optionMetadata.get(itemValue);
      if (!option && process.env.NODE_ENV !== "production") {
        console.warn(
          `Select: ignoring activation of value "${itemValue}" — no SelectItem with this value is registered.`,
        );
      }
      if (disabled || !option || option.disabled || !matchesSearch(option.label, searchQuery))
        return;
      setNativeInvalid(false);
      if (multiple) {
        setValue((prev) => {
          const current = Array.isArray(prev) ? prev : [];
          return current.includes(itemValue)
            ? current.filter((v) => v !== itemValue)
            : [...current, itemValue];
        });
      } else {
        setValue(itemValue);
        handleOpenChange(false);
        triggerRef.current?.focus();
      }
    },
    [disabled, multiple, optionMetadata, searchQuery, setValue, handleOpenChange],
  );

  // Reset clears both the value AND the post-submit invalid presentation so
  // aria-invalid does not keep announcing after the form resets, matching native
  // :user-invalid semantics (form reset clears the user-interacted flag).
  const resetValueAndValidity = useCallback(
    (next: SelectValue) => {
      setNativeInvalid(false);
      setValue(next);
    },
    [setValue],
  );
  useFormReset(wrapperRef, resetValue, resetValueAndValidity, !isValueControlled);

  const hasRequiredValue = Array.isArray(value) ? value.length > 0 : value !== null && value !== "";
  const resolvedAriaInvalid = nativeInvalid && required && !hasRequiredValue ? true : ariaInvalid;

  // Stable ref required: dep of the contextValue memo below.
  const onNativeInvalid = useCallback(() => {
    setNativeInvalid(true);
    (searchInputRef.current ?? triggerRef.current)?.focus();
  }, []);

  const contextValue: SelectContextValue = useMemo(
    () => ({
      open: isOpen,
      disabled,
      searchable,
      onOpenChange: handleOpenChange,
      value,
      multiple,
      searchQuery,
      onSearchChange,
      highlighted,
      setHighlighted,
      selectItem,
      registerOption,
      unregisterOption,
      options: optionMetadata,
      triggerRef,
      contentRef,
      searchInputRef,
      variant,
      listboxId,
      triggerId: triggerIdProp ?? `${listboxId}-trigger`,
      ariaInvalid: resolvedAriaInvalid,
      ariaDescribedBy,
      ariaLabelledBy,
      required: required || undefined,
      onNativeInvalid,
    }),
    [
      isOpen,
      disabled,
      searchable,
      handleOpenChange,
      value,
      multiple,
      searchQuery,
      onSearchChange,
      highlighted,
      setHighlighted,
      selectItem,
      registerOption,
      unregisterOption,
      optionMetadata,
      variant,
      listboxId,
      triggerIdProp,
      resolvedAriaInvalid,
      ariaDescribedBy,
      ariaLabelledBy,
      required,
      onNativeInvalid,
    ],
  );

  return { contextValue, wrapperRef };
}
